using Microsoft.AspNetCore.HttpOverrides;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddScoped<IUserService, UserService>();
builder.Services.AddSingleton<ICacheService>(sp =>
    new CacheService(sp.GetRequiredService<IUserService>()));
builder.Services.AddHttpClient("api")
    // Breaking change 1: ConfigureHttpMessageHandlerBuilder was removed in .NET 9.
    // Replace with ConfigurePrimaryHttpMessageHandler.
    .ConfigurePrimaryHttpMessageHandler(() =>
        new HttpClientHandler { UseCookies = false })
    // Breaking change 2: .NET 9 redacts all HTTP header values in IHttpClientFactory
    // logs by default. Disable redaction to preserve Trace-level header debugging.
    .RedactLoggedHeaders(_ => false);
builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
});
var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

